#define MAX_PX         110.0f

// "Level" thresholds
#define LEVEL_GOOD_DEG 0.5f
#define LEVEL_OK_DEG   1.5f

// Clamp display range (deg)
#define ROLL_CLAMP_DEG  20.0f
#define PITCH_CLAMP_DEG 23.0f

// NVS
#define NVS_NS         "leveler"
#define NVS_KEY_ROLL0  "roll0_md"   // milli-degrees, int32
#define NVS_KEY_PITCH0 "pitch0_md"  // milli-degrees, int32
#define NVS_KEY_MUTE   "aud_muted"  // u8 0/1
#define NVS_KEY_VOL    "aud_vol"    // u8 0-100

